// Step 1: Sammle alle relevanten Daten aus Supabase
const scanDate = new Date().toISOString().split('T')[0];
const oneMonthAgo = new Date(Date.now() - 30*86400000).toISOString().split('T')[0];
const threeMonthsAgo = new Date(Date.now() - 90*86400000).toISOString().split('T')[0];
const sixMonthsAgo = new Date(Date.now() - 180*86400000).toISOString().split('T')[0];
const oneYearAgo = new Date(Date.now() - 365*86400000).toISOString().split('T')[0];
const in30d = new Date(Date.now() + 30*86400000).toISOString().split('T')[0];

const supaFetch = async (path) => {
  const resp = await fetch(`${$env.SUPABASE_URL}/rest/v1/${path}`, {
    headers: {
      'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
      'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`
    },
    signal: AbortSignal.timeout(10000)
  });
  const data = await resp.json();
  return Array.isArray(data) ? data : [];
};

// Wealth Snapshots
const snapshots = await supaFetch('wealth_snapshots?order=snapshot_date.desc&limit=12');
const currentWealth = snapshots[0] || null;

// Budget
const budget = await supaFetch('budget?order=created_at.desc&limit=12');

// Portfolio Holdings
const holdings = await supaFetch('portfolio_holdings?select=*');

// Properties
const properties = await supaFetch('properties?status=eq.active&select=*');

// Actions + Deadlines next 30 days
const actions = await supaFetch(`actions?deadline=lte.${in30d}&status=neq.done&order=deadline.asc`);

// Calendar Events next 30 days
const events = await supaFetch(`calendar_events?event_date=gte.${scanDate}&event_date=lte.${in30d}&status=eq.upcoming&order=event_date.asc`);

// Milestones
const milestones = await supaFetch('milestones?order=priority.asc');

// Country Stability (latest)
const stability = await supaFetch('country_stability?order=scan_date.desc&limit=20');

// Agent costs this month
const agentCosts = await supaFetch(`agent_logs?created_at=gte.${oneMonthAgo}&select=agent_name,cost_eur`);
const totalAgentCost = agentCosts.reduce((sum, a) => sum + (parseFloat(a.cost_eur) || 0), 0);

// Latest scan results
const scanResults = await supaFetch('monthly_scan_results?order=scan_date.desc&limit=1');

// FX rates
const fxRates = await supaFetch('fx_rates?order=scan_date.desc&limit=10');

// Savings goals
const savingsGoals = await supaFetch('savings_goals?select=*');

// Macro indicators
const macro = await supaFetch('macro_indicators?order=scan_date.desc&limit=1');

// Exit prerequisites
const exitPrereqs = await supaFetch('exit_prerequisites?select=*');
const exitCompleted = exitPrereqs.filter(e => e.status === 'done').length;
const exitTotal = exitPrereqs.length;
const exitReadiness = exitTotal > 0 ? Math.round(exitCompleted / exitTotal * 100) : 0;

return [{ json: {
  scan_date: scanDate,
  wealth: { current: currentWealth, history: snapshots },
  budget,
  holdings,
  properties,
  actions,
  events,
  milestones,
  stability,
  agent_cost_month: Math.round(totalAgentCost * 100) / 100,
  scan_results: scanResults[0] || null,
  fx_rates: fxRates,
  savings_goals: savingsGoals,
  macro: macro[0] || null,
  exit_readiness: exitReadiness,
  exit_completed: exitCompleted,
  exit_total: exitTotal
}}];

// Step 2: Stress-Test Snapshot (Code Node, kein LLM)
const data = $input.first().json;
const holdings = data.holdings || [];

// Calculate total portfolio value
const totalPortfolio = holdings.reduce((sum, h) => {
  return sum + ((parseFloat(h.current_price) || 0) * (parseFloat(h.shares) || 0));
}, 0);

// Stress scenarios
const scenarios = {
  'crash_2008': { equity: -0.50, bonds: -0.05, crypto: -0.80, gold: 0.25, real_estate: -0.20, label: '2008 Finanzkrise' },
  'covid_2020': { equity: -0.34, bonds: 0.05, crypto: -0.50, gold: 0.10, real_estate: -0.05, label: 'COVID-19 Crash' }
};

const stressResults = {};
for (const [key, scenario] of Object.entries(scenarios)) {
  let stressedValue = 0;
  for (const h of holdings) {
    const value = (parseFloat(h.current_price) || 0) * (parseFloat(h.shares) || 0);
    const type = (h.type || '').toLowerCase();
    let factor = 0;
    if (type.includes('aktie') || type.includes('etf') || type.includes('stock')) factor = scenario.equity;
    else if (type.includes('anleihe') || type.includes('bond')) factor = scenario.bonds;
    else if (type.includes('krypto') || type.includes('crypto')) factor = scenario.crypto;
    else if (type.includes('gold') || type.includes('edelmetall')) factor = scenario.gold;
    else factor = scenario.equity; // default to equity
    stressedValue += value * (1 + factor);
  }
  stressResults[key] = {
    label: scenario.label,
    original: Math.round(totalPortfolio),
    stressed: Math.round(stressedValue),
    loss_pct: totalPortfolio > 0 ? Math.round((stressedValue - totalPortfolio) / totalPortfolio * 100) : 0
  };
}

return [{ json: { ...data, stress_test: stressResults, total_portfolio: Math.round(totalPortfolio) } }];

// Step 3: Korrelations-Check (Klumpenrisiko)
const data = $input.first().json;
const holdings = data.holdings || [];
const properties = data.properties || [];

const totalPortfolio = data.total_portfolio || 0;
const totalPropertyValue = properties.reduce((sum, p) => sum + (parseFloat(p.current_value) || 0), 0);
const totalAssets = totalPortfolio + totalPropertyValue;

// Currency concentration
const byCurrency = {};
for (const h of holdings) {
  const cur = h.currency || 'EUR';
  byCurrency[cur] = (byCurrency[cur] || 0) + ((parseFloat(h.current_price) || 0) * (parseFloat(h.shares) || 0));
}
// Properties are EUR
byCurrency['EUR'] = (byCurrency['EUR'] || 0) + totalPropertyValue;

const maxCurrencyPct = totalAssets > 0 ? Math.max(...Object.values(byCurrency)) / totalAssets * 100 : 0;
const maxCurrencyName = Object.entries(byCurrency).sort((a, b) => b[1] - a[1])[0]?.[0] || 'EUR';

// Geography concentration
const byGeo = {};
for (const h of holdings) {
  const dom = h.domicile || 'unknown';
  byGeo[dom] = (byGeo[dom] || 0) + ((parseFloat(h.current_price) || 0) * (parseFloat(h.shares) || 0));
}
byGeo['DE'] = (byGeo['DE'] || 0) + totalPropertyValue;
const maxGeoPct = totalAssets > 0 ? Math.max(...Object.values(byGeo)) / totalAssets * 100 : 0;
const maxGeoName = Object.entries(byGeo).sort((a, b) => b[1] - a[1])[0]?.[0] || 'DE';

// Liquidity (illiquid = properties + locked assets)
const illiquidPct = totalAssets > 0 ? totalPropertyValue / totalAssets * 100 : 0;

const correlationScores = {
  currency: { max_pct: Math.round(maxCurrencyPct), dominant: maxCurrencyName, flag: maxCurrencyPct > 60 },
  geography: { max_pct: Math.round(maxGeoPct), dominant: maxGeoName, flag: maxGeoPct > 60 },
  liquidity: { illiquid_pct: Math.round(illiquidPct), flag: illiquidPct > 60 }
};

return [{ json: { ...data, correlation_scores: correlationScores } }];

// Step 4: Sonnet Call - Weekly Intelligence Brief
const data = $input.first().json;

const isFirstWeekOfMonth = new Date().getDate() <= 7;
const reportType = isFirstWeekOfMonth ? 'monthly' : 'weekly';

// Build context for Sonnet
const context = {
  scan_date: data.scan_date,
  report_type: reportType,
  wealth: data.wealth?.current || 'Keine Daten',
  portfolio_total: data.total_portfolio,
  properties: (data.properties || []).map(p => ({
    name: p.name, equity: (parseFloat(p.current_value) || 0) - (parseFloat(p.loan_amount_current) || 0),
    loan: p.loan_amount_current, value: p.current_value
  })),
  holdings_count: (data.holdings || []).length,
  top_holdings: (data.holdings || []).sort((a, b) => ((parseFloat(b.current_price)||0)*(parseFloat(b.shares)||0)) - ((parseFloat(a.current_price)||0)*(parseFloat(a.shares)||0))).slice(0, 5).map(h => ({ name: h.name, value: Math.round((parseFloat(h.current_price)||0)*(parseFloat(h.shares)||0)) })),
  stress_test: data.stress_test,
  correlation_scores: data.correlation_scores,
  alerts: data.scan_results?.alerts || [],
  actions_pending: (data.actions || []).length,
  events_upcoming: (data.events || []).length,
  exit_readiness: data.exit_readiness,
  agent_cost_month: data.agent_cost_month,
  macro: data.macro,
  fx_rates: (data.fx_rates || []).slice(0, 5)
};

const systemPrompt = `Du bist der Personal CFO. Schreibe einen ${reportType === 'monthly' ? 'ausführlichen Monatsbericht' : 'wöchentlichen Portfolio-Narrativ'} in 4 Absätzen. Ton: Wie ein persönlicher CFO beim Frühstücks-Briefing — klar, direkt, keine unnötige Fachsprache.

Absatz 1 — WAS IST PASSIERT:
Nettovermögen, Haupttreiber, Immobilien-Equity durch Tilgung.

Absatz 2 — KONTEXT:
Portfolio-Performance vs. Zielrendite. Klumpenrisiko-Status. OSINT: Zielländer stabil/Veränderung. Stress-Test Ergebnis.

Absatz 3 — HANDLUNGSBEDARF:
1-3 priorisierte Aktionen. Fristen die anstehen.

Absatz 4 — AUSBLICK:
Exit-Readiness. Nächste Meilensteine. GeoArbitrage-Roadmap Status.

Antworte auf Deutsch. Maximal 800 Wörter.`;

try {
  const resp = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': $env.ANTHROPIC_API_KEY,
      'anthropic-version': '2023-06-01'
    },
    body: JSON.stringify({
      model: $env.MODEL_SONNET || 'claude-sonnet-4-6',
      max_tokens: 1500,
      system: systemPrompt,
      messages: [{ role: 'user', content: JSON.stringify(context) }]
    }),
    signal: AbortSignal.timeout(60000)
  });
  const result = await resp.json();
  const narrative = result.content?.[0]?.text || 'Report konnte nicht erstellt werden.';
  const tokens_in = result.usage?.input_tokens || 0;
  const tokens_out = result.usage?.output_tokens || 0;

  return [{ json: { ...data, narrative, report_type: reportType, tokens_in, tokens_out } }];
} catch (e) {
  return [{ json: { ...data, narrative: `Fehler bei Report-Erstellung: ${e.message}`, report_type: reportType, tokens_in: 0, tokens_out: 0 } }];
}

// Step 5+6: Save to Supabase + Prepare Telegram
const data = $input.first().json;

// Save full report to monthly_reports
const reportRow = {
  scan_date: data.scan_date,
  report_type: data.report_type,
  narrative: data.narrative,
  stress_test_results: data.stress_test || {},
  correlation_scores: data.correlation_scores || {},
  actions: (data.actions || []).map(a => ({ title: a.title, deadline: a.deadline })),
  countries_scanned: data.scan_results?.countries_scanned || [],
  alerts_triggered: data.scan_results?.alerts || [],
  cost_eur: 0,
  delivery_status: 'delivered'
};

await fetch(`${$env.SUPABASE_URL}/rest/v1/monthly_reports`, {
  method: 'POST',
  headers: {
    'apikey': $env.SUPABASE_SERVICE_ROLE_KEY,
    'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
    'Content-Type': 'application/json',
    'Prefer': 'return=minimal'
  },
  body: JSON.stringify(reportRow),
  signal: AbortSignal.timeout(10000)
});

// Telegram short version (max 500 chars)
let telegramText = data.narrative || '';
// Extract first paragraph
const firstParagraph = telegramText.split('\n\n')[0] || telegramText;
let shortMessage = firstParagraph.substring(0, 450);
if (shortMessage.length < firstParagraph.length) shortMessage += '...';
shortMessage += '\n\n📊 Vollständiger Brief im Dashboard';

return [{ json: {
  message: shortMessage,
  urgency: 'green',
  category: 'weekly_report'
}}];

// Log the report generation
const data = $('Step 4: Sonnet Brief').first().json;
return [{ json: {
  session_id: `weekly_report_${data.scan_date}`,
  agent_name: 'weekly_report',
  model: $env.MODEL_SONNET || 'claude-sonnet-4-6',
  input_summary: `Weekly Report ${data.scan_date}`,
  output_summary: `${data.report_type} report generated, ${data.narrative?.length || 0} chars`,
  tokens_in: data.tokens_in || 0,
  tokens_out: data.tokens_out || 0
}}];
